export const berlinSpots = [
  { id:'berlin-teufelsberg', name:'Teufelsberg', city:'Berlin', country:'Germany', shortDesc:'Cold War NSA listening station atop a hill of WWII rubble in Grunewald', fullDesc:'A former US NSA field station on an artificial hill built from 400,000 tonnes of WWII rubble in the Grunewald forest. The golf-ball radomes are intact, the interiors covered in extraordinary graffiti, and the views from the dome tops across Berlin are remarkable.', whyHidden:'Requires a bus and 20-minute walk through Grunewald forest. Post-industrial context and access requirements keep mainstream tourists away.', bestTime:'Weekend afternoons when guided access is available', howToGet:'S7 to Heerstraße, then Bus 218 to Teufelsseechaussee, 20-minute walk.', whatToAvoid:'Weekday solo access restricted — book a weekend guided visit online', hiddennessScore:7, category:'Architecture / Landmark', interests:['history','photography','unusual'], lat:52.4964, lng:13.2393, address:'Teufelsseechaussee 10, Berlin', entryPrice:'€8', photo:'1560969184-10fe8719e047' },
  { id:'berlin-clarchen-ballhaus', name:"Clärchens Ballhaus", city:'Berlin', country:'Germany', shortDesc:'1913 dance hall intact — ballroom dancing Sundays, Berlin\'s most romantic venue', fullDesc:'A dance hall built in 1913 that survived both World Wars with its original stucco ceiling, balconies and sprung dance floor. Sunday afternoon features ballroom dancing to live music. Nothing about the building or programme has been modernised in over a century.', whyHidden:'Located in Mitte but completely off tourist maps. The ballroom context — old-fashioned partner dancing, live band — puts off most international visitors.', bestTime:'Sunday afternoon tango session from 4pm; Friday DJ nights', howToGet:'U8 to Rosenthaler Platz, 10-minute walk east.', whatToAvoid:'Closed Tuesday and Wednesday', hiddennessScore:8, category:'Underground / Subculture', interests:['nightlife','art'], lat:52.5281, lng:13.4020, address:'Auguststraße 24, Berlin', entryPrice:'Free / small entry', photo:'1560969184-10fe8719e047' },
  { id:'berlin-silent-green', name:'Silent Green', city:'Berlin', country:'Germany', shortDesc:'1909 crematorium turned contemporary arts venue in Wedding', fullDesc:'A 1909 municipal crematorium in Wedding with extraordinary Art Nouveau architecture converted into a contemporary culture centre hosting concerts, film and art in the original ceremonial halls. The Columbiahalle beneath the main building is one of Berlin\'s finest mid-size concert rooms.', whyHidden:'In Wedding, a neighbourhood most tourists never visit. The subject matter — a crematorium — also discourages casual visitors.', bestTime:'When a significant event is scheduled; the gardens are open daily', howToGet:'U9 to Leopoldplatz, 5-minute walk north.', whatToAvoid:'Nothing on during the day without a scheduled event', hiddennessScore:9, category:'Underground / Subculture', interests:['art','nightlife','photography'], lat:52.5467, lng:13.3601, address:'Gerichtstraße 35, Berlin', entryPrice:'Varies', photo:'1560969184-10fe8719e047' },
  { id:'berlin-volkspark-friedrichshain', name:'Volkspark Friedrichshain', city:'Berlin', country:'Germany', shortDesc:'19th-century park with a Brothers Grimm fountain and two WWII bunker hills', fullDesc:'A 52-hectare park in Friedrichshain with an extraordinary 1913 fairy-tale fountain (Märchenbrunnen) depicting Brothers Grimm characters, a large outdoor pool, and two artificial hills made from WWII rubble containing a buried bunker. The beer garden is the best in eastern Berlin.', whyHidden:'The park is known but the Märchenbrunnen fountain is consistently overlooked even by Berliners.', bestTime:'Summer afternoons for the beer garden; spring for the fountain', howToGet:'U5 to Samariterstraße, or Tram M10.', whatToAvoid:'The western entrance is less interesting — go directly to Märchenbrunnen', hiddennessScore:6, category:'Park / Green Space', interests:['relaxation','photography'], lat:52.5263, lng:13.4399, address:'Am Friedrichshain, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-computerspielemuseum', name:'Computerspielemuseum', city:'Berlin', country:'Germany', shortDesc:'World\'s first permanent video game museum — genuinely interactive', fullDesc:'The world\'s first permanent museum dedicated to the history of video games, on Karl-Marx-Allee in Friedrichshain. The collection spans from 1950s mainframe games to the present, with playable exhibits from every era. The Stalinist boulevard location adds an extraordinary architectural context.', whyHidden:'On Karl-Marx-Allee in the east — a district most tourists don\'t explore. Niche subject masks a genuinely moving museum.', bestTime:'Weekday afternoons when it\'s quiet', howToGet:'U5 to Weberwiese.', whatToAvoid:'School group visits on Thursday mornings', hiddennessScore:7, category:'Museum / History', interests:['museums','unusual'], lat:52.5134, lng:13.4549, address:'Karl-Marx-Allee 93a, Berlin', entryPrice:'€9', photo:'1560969184-10fe8719e047' },
  { id:'berlin-tempelhof-field', name:'Tempelhofer Feld', city:'Berlin', country:'Germany', shortDesc:'Hitler\'s airport turned 386-hectare public park — largest open space in Berlin', fullDesc:'The runways and taxiways of the former Tempelhof airport, closed in 2008, converted into a vast public park used by cyclists, rollerbladers, kite-flyers and urban gardeners. The Fascist-era terminal building — 1.2km long — runs along the edge. The scale of the open space inside a capital city is extraordinary.', whyHidden:'Berlin residents know it; tourists rarely make the 15-minute U-Bahn journey. Flat runways don\'t read as a tourist attraction from the outside.', bestTime:'Any clear afternoon — golden hour on the runway is spectacular', howToGet:'U6 to Tempelhof or U8 to Boddinstraße.', whatToAvoid:'Very popular on weekends in summer but large enough to absorb crowds', hiddennessScore:5, category:'Park / Green Space', interests:['hiking','photography','unusual'], lat:52.4733, lng:13.4028, address:'Tempelhofer Damm 1-7, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-karl-marx-allee', name:'Karl-Marx-Allee', city:'Berlin', country:'Germany', shortDesc:'Stalinist boulevard with original 1960s GDR cafés intact', fullDesc:'A 2.3km Stalinist boulevard built from 1952–1960 in the Soviet "wedding cake" style. The original Café Moskau and Cinema International survive, and several neighbourhood cafés in the ground-floor units remain unchanged since the 1960s. Walking its full length reveals a completely different Berlin.', whyHidden:'Most visitors see the boulevard from a bus window. The surviving GDR-era restaurants in the base units require walking — few people do it.', bestTime:'Weekday mornings for the unreconstructed local cafés', howToGet:'U5 to Strausberger Platz or Weberwiese.', whatToAvoid:'Nothing — it is a public street', hiddennessScore:7, category:'Architecture / Landmark', interests:['history','monuments','photography'], lat:52.5166, lng:13.4448, address:'Karl-Marx-Allee, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-naturkunde-museum', name:'Museum für Naturkunde', city:'Berlin', country:'Germany', shortDesc:'World\'s tallest mounted dinosaur — superb natural history museum', fullDesc:'Berlin\'s natural history museum holds the world\'s largest mounted dinosaur skeleton (a Brachiosaurus brancai at 13.27 metres), an extraordinary mineral and meteorite collection, and spectacular Victorian specimen storage rooms visible through glass panels. One of the greatest natural history museums in the world.', whyHidden:'Natural history museums are undersold in Berlin where arts dominate tourist attention. The Brachiosaurus alone is worth the trip.', bestTime:'Weekday mornings', howToGet:'U6 to Naturkundemuseum.', whatToAvoid:'School groups fill the dinosaur halls Tuesday to Thursday mornings', hiddennessScore:4, category:'Museum / History', interests:['museums','unusual'], lat:52.5304, lng:13.3810, address:'Invalidenstraße 43, Berlin', entryPrice:'€8', photo:'1560969184-10fe8719e047' },
  { id:'berlin-spreepark', name:'Spreepark Ruins', city:'Berlin', country:'Germany', shortDesc:'Abandoned 1969 East German theme park — Ferris wheel and rusting rides', fullDesc:'A former GDR theme park in the Plänterwald forest, abandoned in 2001 after the operator fled to Peru. Now a partially restored cultural venue with guided tours. The eerie rusting Ferris wheel, swan boats and carousels in the forest are among Europe\'s most compelling urban ruins.', whyHidden:'Access by guided tour only; the Plänterwald location is 30 minutes from the centre. GDR context requires some historical knowledge.', bestTime:'Weekend guided tours — book in advance', howToGet:'S8/S9 to Treptower Park, then a 20-minute walk or summer ferry.', whatToAvoid:'Do not enter without a guide — the perimeter is monitored', hiddennessScore:8, category:'Unusual / Weird', interests:['photography','history','unusual'], lat:52.4699, lng:13.5011, address:'Kiehnwerderallee, Berlin', entryPrice:'€20', photo:'1560969184-10fe8719e047' },
  { id:'berlin-flohmarkt-mauerpark', name:'Flohmarkt am Mauerpark', city:'Berlin', country:'Germany', shortDesc:'Sunday flea market on the former Berlin Wall death strip', fullDesc:'A large Sunday flea market on the site of a former Berlin Wall death strip in Prenzlauer Berg — genuine second-hand dealers, vintage clothes, vinyl, antiques and street food. The adjacent park hosts a popular open-air karaoke amphitheatre. One of the best Sunday markets in Europe.', whyHidden:'More of a local institution than a tourist attraction, despite being one of Berlin\'s best experiences. The authentic non-tourist stalls reward early arrival.', bestTime:'Sunday mornings from 9am; arrive early for the best vinyl', howToGet:'U2 to Eberswalder Straße.', whatToAvoid:'After midday on summer Sundays the karaoke crowd overtakes the market', hiddennessScore:4, category:'Market / Street Food', interests:['markets','nightlife','art'], lat:52.5408, lng:13.4030, address:'Bernauer Straße, Mauerpark, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-wedding', name:'Wedding Neighbourhood', city:'Berlin', country:'Germany', shortDesc:'Working-class Berlin district where artists go when Mitte gets expensive', fullDesc:'A traditionally working-class district north of Mitte that has attracted studios, galleries and independent restaurants without the aggressive gentrification of Mitte or Prenzlauer Berg. The Leopoldplatz square, Gerichtstraße cultural venues and the Panke canal are anchors of a genuine alternative cultural scene.', whyHidden:'Wedding has a stigma in tourist guides as a rough neighbourhood. This is largely outdated — the arts and restaurant scene are increasingly excellent.', bestTime:'Any weekday afternoon; evening for the bar scene', howToGet:'U6 or U9 to Leopoldplatz; or S41/S42 ring to Wedding.', whatToAvoid:'Nothing specific', hiddennessScore:8, category:'Neighbourhood / District', interests:['art','nightlife','food'], lat:52.5467, lng:13.3601, address:'Wedding, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },

  // ── SECOND PASS ────────────────────────────────────────────────────────────
  { id:'berlin-neukölln-weichselplatz', name:'Neukölln — Weichselstraße and Reuterplatz', city:'Berlin', country:'Germany', shortDesc:'The neighbourhood that replaced Mitte as Berlin\'s creative centre — bars, studios, street food', fullDesc:'The streets around Weichselstraße and Reuterplatz in northern Neukölln have the most concentrated independent bar and restaurant scene in Berlin, replacing the gentrified Mitte of the early 2000s. Shawarma stands, natural wine bars, gallery basements and döner shops coexist on a single block. The neighbourhood still has Turkish and Arab community anchors alongside the creative scene.', whyHidden:'Neukölln is off the tourist map — U8 to Herrmannplatz or Rathaus Neukölln feels suburban. Those who go find the most authentic version of current Berlin.', bestTime:'Thursday–Sunday evenings; Saturday morning for the Turkish market', howToGet:'U8 to Herrmannplatz or Rathaus Neukölln, walk north into the Weichselkiez.', whatToAvoid:'Nothing specific', hiddennessScore:6, category:'Neighbourhood / District', interests:['nightlife','food','art'], lat:52.4836, lng:13.4373, address:'Weichselstraße, Neukölln, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-türkischer-markt', name:'Türkischer Markt, Maybachufer', city:'Berlin', country:'Germany', shortDesc:'Berlin\'s Turkish market on a canal — the best market in the city', fullDesc:'A twice-weekly street market along the Maybachufer canal in Neukölln/Kreuzberg, Tuesday and Friday afternoons, with the finest fresh produce in Berlin: Anatolian cheeses, dried herbs and spices, Turkish bread, fresh olives, pekmez (grape molasses) and Turkish pastries. The canal setting and the community atmosphere are extraordinary.', whyHidden:'In Neukölln/Kreuzberg, requiring a U-Bahn journey south. The Markthalle Neun in Kreuzberg gets tourist press; this market is more authentic and more interesting.', bestTime:'Friday afternoon from noon; Tuesday afternoon is less crowded', howToGet:'U8 to Schönleinstraße, walk to the canal.', whatToAvoid:'Closes by 6:30pm; reduced stalls on Tuesday compared to Friday', hiddennessScore:6, category:'Market / Street Food', interests:['food','markets'], lat:52.4902, lng:13.4193, address:'Maybachufer, Neukölln, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-hamburgerbahnhof', name:'Hamburger Bahnhof', city:'Berlin', country:'Germany', shortDesc:'Berlin\'s contemporary art museum in a 19th-century railway station — one of Europe\'s finest', fullDesc:'A neoclassical 1847 railway station converted into one of Europe\'s greatest contemporary art museums, with a permanent collection including Joseph Beuys\'s full archive, Andy Warhol, Cy Twombly and a programme of major international exhibitions. The Rieckhallen extension behind adds 13,000 square metres of exhibition space.', whyHidden:'Overshadowed by the Museum Island institutions. The contemporary art collection here is equal to Tate Modern and the building extraordinary.', bestTime:'Weekday mornings for empty galleries', howToGet:'S3/S5/S7/S9 to Berlin Hauptbahnhof; walk 10 minutes north to Invalidenstraße 50.', whatToAvoid:'Closed Monday', hiddennessScore:4, category:'Gallery / Art', interests:['art','museums','monuments'], lat:52.5302, lng:13.3731, address:'Invalidenstraße 50-51, Berlin', entryPrice:'€14', photo:'1560969184-10fe8719e047' },
  { id:'berlin-neue-nationalgalerie', name:'Neue Nationalgalerie', city:'Berlin', country:'Germany', shortDesc:'Mies van der Rohe\'s 1968 glass temple — the finest modern building in Berlin', fullDesc:'Ludwig Mies van der Rohe\'s last major commission, completed 1968, is a single-storey glass pavilion raised on a granite plinth — a perfect square roof supported by eight cross-shaped steel columns with no internal walls. The glass box appears to float. The building is one of the greatest works of 20th-century architecture; the permanent collection of 20th-century German painting is excellent.', whyHidden:'In the Kulturforum, a museum district tourists bypass for Museum Island. The building alone — one of Mies\'s masterworks — is reason enough to visit.', bestTime:'Weekday mornings; the building is most atmospheric in grey weather when the glass merges with the sky', howToGet:'S1/S2/S25 or U2 to Potsdamer Platz, 5-minute walk west.', whatToAvoid:'Closed Tuesday', hiddennessScore:4, category:'Architecture / Landmark', interests:['art','monuments','photography'], lat:52.5079, lng:13.3716, address:'Potsdamer Straße 50, Berlin', entryPrice:'€14', photo:'1560969184-10fe8719e047' },
  { id:'berlin-markthalle-neun', name:'Markthalle Neun', city:'Berlin', country:'Germany', shortDesc:'1891 market hall in Kreuzberg revived as the best permanent food hall in Berlin', fullDesc:'A 19th-century iron-and-glass market hall in Kreuzberg, restored in 2011 and now operating as a permanent market with artisan food producers, a butcher, fishmonger, coffee roaster and restaurant. The Thursday Street Food Thursday market is the most famous event; the regular market is better.', whyHidden:'Kreuzberg tourists focus on the Bergmannkiez; Markthalle Neun requires a walk east. The regular (non-Street-Food-Thursday) market is the most authentic version.', bestTime:'Tuesday and Friday for the regular market; avoid Street Food Thursday if you want the local version', howToGet:'U1/U3 to Görlitzer Bahnhof, 5-minute walk north.', whatToAvoid:'Street Food Thursday draws large tourist crowds — the regular market is better', hiddennessScore:4, category:'Market / Street Food', interests:['food','markets'], lat:52.4989, lng:13.4352, address:'Eisenbahnstraße 42-43, Kreuzberg, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-sowjetisches-ehrenmal-treptow', name:'Soviet War Memorial Treptower Park', city:'Berlin', country:'Germany', shortDesc:'The largest Soviet war memorial outside Russia — 5,000 soldiers buried under the lawns', fullDesc:'A monumental complex in Treptower Park dedicated to the 80,000 Soviet soldiers who died in the Battle of Berlin (1945). The avenue of weeping birches leads to a sunken space flanked by 16 granite sarcophagi, ending at a 12-metre bronze soldier standing on a shattered swastika. 5,000 soldiers are buried under the lawns. The scale and ambition of the memorial is extraordinary.', whyHidden:'In Treptow, a southern district most tourists never visit. The memorial is the most significant Second World War monument in Germany and receives a fraction of its deserved visitors.', bestTime:'Any quiet weekday; dawn or dusk for the most atmospheric light', howToGet:'S6/S8/S9 to Treptower Park.', whatToAvoid:'Nothing — the park is always accessible', hiddennessScore:5, category:'Museum / History', interests:['monuments','history','photography'], lat:52.4747, lng:13.4697, address:'Treptower Park, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-berliner-mauer-memorial', name:'Berliner Mauer Memorial', city:'Berlin', country:'Germany', shortDesc:'The most complete surviving section of the Berlin Wall — the death strip intact', fullDesc:'A 1.4km preserved section of the Berlin Wall on Bernauer Straße, including the complete border fortification — outer wall, death strip, watchtowers, signal fencing and inner wall — exactly as it existed until 1989. The Documentation Centre tells individual stories of escape attempts and deaths. The most important Wall site.', whyHidden:'The East Side Gallery is better known as a tourist attraction. The Bernauer Straße memorial is more historically complete and more moving.', bestTime:'Any morning; the Documentation Centre requires 2 hours', howToGet:'S1/S2/S25 or U8 to Nordbahnhof.', whatToAvoid:'Avoid summer weekends when it gets busy', hiddennessScore:3, category:'Museum / History', interests:['history','monuments','photography'], lat:52.5350, lng:13.3831, address:'Bernauer Straße 111, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-stasi-museum-lichtenberg', name:'Stasi Museum', city:'Berlin', country:'Germany', shortDesc:'The actual Stasi headquarters building — Erich Mielke\'s office preserved exactly as left', fullDesc:'The former operational headquarters of the East German secret police (Stasi) in Lichtenberg, including Erich Mielke\'s preserved office suite, the communications centre, interrogation facilities and the full documentation of how the Stasi surveilled 6 million East Germans. The building complex is vast; the intact operational rooms are extraordinary.', whyHidden:'In Lichtenberg, an eastern district tourists rarely visit. The combination of intact Cold War bureaucratic hardware and the scale of documented surveillance is unlike any other museum in Europe.', bestTime:'Any weekday; the audio guide is essential', howToGet:'U5 to Magdalenenstraße.', whatToAvoid:'Closed Monday; the full visit requires 3+ hours', hiddennessScore:6, category:'Museum / History', interests:['museums','history'], lat:52.5112, lng:13.4974, address:'Ruschestraße 103, Lichtenberg, Berlin', entryPrice:'€8', photo:'1560969184-10fe8719e047' },
  { id:'berlin-wannsee-conference-house', name:'Wannsee Conference House', city:'Berlin', country:'Germany', shortDesc:'The villa where the Holocaust was organised in 90 minutes in 1942', fullDesc:'A lakeside villa in Wannsee where on January 20, 1942, fifteen senior Nazi officials met for 90 minutes to coordinate the "Final Solution" — the systematic murder of Europe\'s Jews. The villa is preserved exactly as it was, with a permanent exhibition including the original conference protocol (the only surviving copy), photographs of the participants and documentation of their subsequent fates.', whyHidden:'Requires an S-Bahn journey to the western suburbs. The concentration of evil in an ordinary-looking lakeside villa — and the 90-minute decision that led to millions of deaths — is the most profoundly disturbing historical space in Germany.', bestTime:'Any morning; plan 2 hours', howToGet:'S1 to Wannsee, then bus 114 to Am Großen Wannsee 56-58.', whatToAvoid:'Nothing — this site should be visited', hiddennessScore:5, category:'Museum / History', interests:['museums','history'], lat:52.4330, lng:13.1636, address:'Am Großen Wannsee 56-58, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-philharmonie', name:'Berliner Philharmonie', city:'Berlin', country:'Germany', shortDesc:'Hans Scharoun\'s 1963 concert hall — a building as radical as its music', fullDesc:'Hans Scharoun\'s 1963 concert hall for the Berlin Philharmonic, with vineyard-terrace seating wrapping 360 degrees around the stage and an asymmetric gold exterior. The acoustic design places the orchestra at the centre of the audience; no seat is more than 32 metres from the podium. The building is the single most important concert hall of the 20th century.', whyHidden:'The Kulturforum location means most tourists walk past it. The exterior is unglamorous in photographs but extraordinary in person; the interior is transformative.', bestTime:'During a concert; guided tours on selected weekdays', howToGet:'S/U Potsdamer Platz, 10-minute walk west.', whatToAvoid:'Concert tickets can be expensive; standing tickets are sold at the door and significantly cheaper', hiddennessScore:3, category:'Architecture / Landmark', interests:['art','monuments'], lat:52.5096, lng:13.3697, address:'Herbert-von-Karajan-Straße 1, Berlin', entryPrice:'€14–100 concert; €6 guided tour', photo:'1560969184-10fe8719e047' },
  { id:'berlin-raw-gelände', name:'RAW Gelände', city:'Berlin', country:'Germany', shortDesc:'Former railway repair yard — Berlin\'s last multi-use alternative cultural space', fullDesc:'A former 1867 railway repair yard in Friedrichshain, 10 hectares of industrial buildings now housing a climbing wall, skate park, flea market, concert venue (Cassiopeia), beach bar, and various cultural venues. Unlike Kulturbrauerei (which has been gentrified), RAW retains its scrappy alternative character.', whyHidden:'On Revaler Straße in Friedrichshain, visible from the S-Bahn but requiring a specific intent. The most authentic surviving large alternative cultural space in Berlin.', bestTime:'Saturday for the flea market and afternoon activities; any evening for the venues', howToGet:'S3/S5/S7/S9 to Warschauer Straße, walk north-west along Revaler Straße.', whatToAvoid:'Some venues are 18+ in the evenings', hiddennessScore:5, category:'Underground / Subculture', interests:['nightlife','markets','art'], lat:52.5111, lng:13.4557, address:'Revaler Straße 99, Friedrichshain, Berlin', entryPrice:'Free (events vary)', photo:'1560969184-10fe8719e047' },
  { id:'berlin-klunkerkranich', name:'Klunkerkranich', city:'Berlin', country:'Germany', shortDesc:'Rooftop bar above a Neukölln shopping centre — Berlin\'s finest secret view', fullDesc:'A bar and garden on the roof of the Neukölln Arcaden shopping centre, with an undeveloped rooftop of gravel, plants and deck chairs looking across the Berlin skyline. The combination of shopping centre elevator, rooftop wilderness and craft beer is quintessentially Berlin.', whyHidden:'Access is through the Karl-Marx-Straße shopping centre elevator — the most improbable route to a genuinely great rooftop bar.', bestTime:'Summer afternoons and evenings; sunset is spectacular', howToGet:'U7 to Karl-Marx-Straße; enter the Neukölln Arcaden and take the lift to the roof.', whatToAvoid:'Closed in winter and bad weather; check klunkerkranich.org', hiddennessScore:7, category:'Bar / Nightlife', interests:['nightlife','photography'], lat:52.4817, lng:13.4339, address:'Karl-Marx-Straße 66 (rooftop), Neukölln, Berlin', entryPrice:'€3 entry', photo:'1560969184-10fe8719e047' },
  { id:'berlin-gropiusbau', name:'Martin-Gropius-Bau', city:'Berlin', country:'Germany', shortDesc:'Berlin\'s finest exhibition building — 1881 Renaissance palazzo beside the Wall', fullDesc:'A restored 1881 building by Martin Gropius (great-uncle of Walter) in a Renaissance palazzo style, housing major temporary exhibitions of art, history and photography. The mosaic-and-terracotta interior courtyard is extraordinary; the building stands directly beside the former Wall. Exhibition quality is consistently among the best in Berlin.', whyHidden:'Overshadowed by the Topography of Terror next door. The building and the programme are outstanding.', bestTime:'Any weekday; check the exhibition programme', howToGet:'S1/S2 or U2 to Potsdamer Platz, 10-minute walk.', whatToAvoid:'Closed Tuesday; between exhibitions', hiddennessScore:4, category:'Gallery / Art', interests:['art','museums','monuments'], lat:52.5046, lng:13.3814, address:'Niederkirchnerstraße 7, Berlin', entryPrice:'€10–16 depending on exhibition', photo:'1560969184-10fe8719e047' },
  { id:'berlin-bergmannkiez', name:'Bergmannstraße, Kreuzberg', city:'Berlin', country:'Germany', shortDesc:'The best neighbourhood street in Berlin for browsing — antiques, delis and Tempodrom', fullDesc:'A pedestrianised section of Bergmannstraße in Kreuzberg lined with organic delis, vintage shops, Turkish greengrocers, independent bookshops and excellent cafés. The adjacent Tempodrom (a permanent tent theatre) and the Marheinekehalle market add to the neighbourhood. This is Kreuzberg as it functions daily, not the tourist Kreuzberg of the Landwehrkanal.', whyHidden:'The southern Kreuzberg Bergmannkiez is known to residents but absent from tourist materials. The Landwehrkanal further north absorbs tourist attention.', bestTime:'Saturday morning for the Marheineke market; any weekday afternoon', howToGet:'U6 to Mehringdamm, walk east on Bergmannstraße.', whatToAvoid:'Nothing specific', hiddennessScore:5, category:'Neighbourhood / District', interests:['food','markets'], lat:52.4921, lng:13.3962, address:'Bergmannstraße, Kreuzberg, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-berliner-unterwelten', name:'Berliner Unterwelten', city:'Berlin', country:'Germany', shortDesc:'Berlin\'s WWII air-raid bunkers and Cold War infrastructure — best underground tours in Europe', fullDesc:'Guided tours into Berlin\'s subterranean infrastructure — WWII air-raid shelters in Gesundbrunnen station, Cold War West Berlin tunnels, and the system of bunkers that sheltered 30,000 civilians during bombing raids. The Gesundbrunnen bunker contains the most complete surviving WWII shelter in Berlin, with original equipment and graffiti.', whyHidden:'Tours must be pre-booked; the entrance is in a U-Bahn station. The underground experience — original wartime equipment, smell of concrete and disinfectant — is unlike any surface museum.', bestTime:'Any tour day — check berliner-unterwelten.de for English tour schedules', howToGet:'U8 to Gesundbrunnen; tours depart from inside the station.', whatToAvoid:'English tours less frequent than German — book specifically', hiddennessScore:6, category:'Underground / Subculture', interests:['history','museums','unusual'], lat:52.5481, lng:13.3880, address:'Brunnenstraße 105, Gesundbrunnen, Berlin', entryPrice:'€15', photo:'1560969184-10fe8719e047' },
  { id:'berlin-tränenpalast', name:'Tränenpalast (Palace of Tears)', city:'Berlin', country:'Germany', shortDesc:'The border crossing where East and West Germans parted — preserved intact', fullDesc:'The former East German border checkpoint at Friedrichstraße station where GDR citizens had to part from Western visitors at the end of each day — giving the building its name "Palace of Tears." The building is preserved and now a free museum using personal testimonies to document the experience of Berlin\'s division. One of the most moving Cold War sites.', whyHidden:'At Friedrichstraße S-Bahn station — thousands of commuters walk past daily without entering. The subject matter and small scale keep it off tourist itineraries.', bestTime:'Any weekday morning', howToGet:'S1/S2/S5/S7 to Friedrichstraße.', whatToAvoid:'Closed Monday', hiddennessScore:5, category:'Museum / History', interests:['museums','history'], lat:52.5231, lng:13.3882, address:'Reichstagufer 17, Mitte, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-nordbahnhof-ghost-station', name:'Nordbahnhof Ghost Station Exhibition', city:'Berlin', country:'Germany', shortDesc:'The Wall ran through Berlin\'s S-Bahn — Nordbahnhof was a ghost station for 28 years', fullDesc:'When the Wall divided Berlin, several S-Bahn stations fell in the border zone and became "ghost stations" — trains passed through but nobody could board. Nordbahnhof station has a free permanent exhibition on its platforms showing photographs of the sealed station and the border fortifications that surrounded it.', whyHidden:'In the S-Bahn station itself — most passengers pass through without noticing the exhibition on the platform walls. The context of being in a station that was sealed for 28 years is eerie and affecting.', bestTime:'Any time the station is open; the quietest experience is early morning', howToGet:'S1/S2/S25 to Nordbahnhof.', whatToAvoid:'Nothing — the exhibition is permanently installed on the platform', hiddennessScore:6, category:'Museum / History', interests:['history','photography'], lat:52.5328, lng:13.3882, address:'Gartenstraße (Nordbahnhof S-Bahn), Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-müggelsee', name:'Müggelsee and Köpenick', city:'Berlin', country:'Germany', shortDesc:'Berlin\'s largest lake — swimming, forests and the perfectly preserved medieval town of Köpenick', fullDesc:'A large lake in southeast Berlin (the largest within the city limits) with sandy beaches, a forest waterfront and a sailing school. The adjacent town of Köpenick has a preserved medieval old town with a castle on a river island — ordinary city tourism completely absent. The journey on the S3 and the lake swim in summer are an entirely different Berlin.', whyHidden:'At the far eastern edge of Berlin requiring the S3 to Köpenick. Berliners know Müggelsee as their summer lake; tourists almost never reach it.', bestTime:'Summer weekdays for uncrowded swimming', howToGet:'S3 to Köpenick, then bus 169 to the lake shore.', whatToAvoid:'Crowded on summer weekends; go on weekdays', hiddennessScore:7, category:'Beach / Water', interests:['beaches','relaxation','hiking'], lat:52.4286, lng:13.6513, address:'Müggelsee, Köpenick, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-botanischer-garten-tropical', name:'Botanischer Garten', city:'Berlin', country:'Germany', shortDesc:'Europe\'s second-largest botanical garden — the tropical greenhouse in winter is extraordinary', fullDesc:'The Berlin Botanical Garden in Dahlem, 43 hectares with 22,000 plant species and a series of large greenhouses including the Palm House — one of the largest glass structures in Europe, with trees of 25 metres growing beneath the iron-and-glass vault. In winter, the Palm House at 25°C while the garden outside is frozen is one of the most extraordinary atmospheric contrasts in the city.', whyHidden:'In Dahlem, south Berlin — a long U-Bahn journey. The tropical greenhouse in winter, the rock garden in spring and the Japanese garden in autumn make this one of the finest botanical gardens in the world.', bestTime:'Winter for the tropical greenhouse; spring for the seasonal garden', howToGet:'U9 to Rathaus Steglitz then bus M48, or S1 to Botanischer Garten.', whatToAvoid:'School groups on Friday mornings', hiddennessScore:5, category:'Park / Green Space', interests:['relaxation','hiking','photography'], lat:52.4520, lng:13.3053, address:'Königin-Luise-Straße 6-8, Dahlem, Berlin', entryPrice:'€7', photo:'1560969184-10fe8719e047' },
  { id:'berlin-hansaviertel', name:'Hansaviertel', city:'Berlin', country:'Germany', shortDesc:'1957 ILA residential estate — every building by a different master modernist', fullDesc:'A residential estate built for the 1957 Interbau exhibition in the Tiergarten district, with individual buildings designed by Alvar Aalto, Oscar Niemeyer, Walter Gropius, Hans Scharoun and 50 other architects from 22 countries. Each building is a separate manifesto. The estate was West Berlin\'s answer to Karl-Marx-Allee.', whyHidden:'In the Tiergarten, between major tourist attractions but invisible because it looks like ordinary housing. Architecture enthusiasts travel from across the world to see this estate; everyone else walks past.', bestTime:'Any clear day for the architecture; the buildings are private residential so exterior only', howToGet:'S5/S7/S9 or U9 to Hauptbahnhof, walk east through the Tiergarten.', whatToAvoid:'Buildings are private — exterior only', hiddennessScore:7, category:'Architecture / Landmark', interests:['monuments','photography'], lat:52.5194, lng:13.3381, address:'Hansaviertel, Tiergarten, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-pfaueninsel', name:'Pfaueninsel (Peacock Island)', city:'Berlin', country:'Germany', shortDesc:'A UNESCO island in the Wannsee with peacocks and a fake Gothic ruin — no cars', fullDesc:'A small island in the Wannsee accessible only by ferry, with a ruined Gothic tower built as a romantic folly by Friedrich Wilhelm II in 1794, a rose garden, palace and wild peacocks. No cars on the island and no buildings after 1830 — the 18th-century romantic landscape is intact.', whyHidden:'Requires an S-Bahn journey to the western suburbs followed by a short bus ride and ferry. Known to Berliners as a summer excursion; most tourists don\'t know it exists.', bestTime:'Spring for the rose garden and peacock courtship displays; any clear day', howToGet:'S7 to Wannsee, then bus 218 to the ferry.', whatToAvoid:'The ferry doesn\'t run in winter; open April to October', hiddennessScore:7, category:'Park / Green Space', interests:['hiking','relaxation','photography'], lat:52.4321, lng:13.1278, address:'Pfaueninsel, Wannsee, Berlin', entryPrice:'€3 ferry + €5 palace', photo:'1560969184-10fe8719e047' },
  { id:'berlin-spandau-altstadt', name:'Spandau Old Town', city:'Berlin', country:'Germany', shortDesc:'Medieval town swallowed by Berlin — half-timbered houses and a Renaissance citadel', fullDesc:'Spandau\'s old town (Altstadt) predates Berlin as a city, with a 16th-century Renaissance citadel, a medieval town hall and half-timbered houses on the market square. The town feels nothing like Berlin — it is a quiet provincial German market town that happens to be on the U7 line.', whyHidden:'At the far western end of the U7 — a 45-minute journey from Mitte. Most Berliners have never been to Spandau. The Renaissance citadel is extraordinary and almost empty.', bestTime:'Weekday mornings; Saturday for the old town market', howToGet:'U7 to Altstadt Spandau (terminal station).', whatToAvoid:'The citadel island is less accessible without a boat in summer', hiddennessScore:7, category:'Architecture / Landmark', interests:['monuments','history','photography'], lat:52.5383, lng:13.2036, address:'Altstadt Spandau, Berlin', entryPrice:'Free (Citadel €4.50)', photo:'1560969184-10fe8719e047' },
  { id:'berlin-berghain-panorama', name:'Berghain / Panorama Bar', city:'Berlin', country:'Germany', shortDesc:'The most influential nightclub in the world — in a 1950s power station in Friedrichshain', fullDesc:'A converted East German power station in Friedrichshain housing two venues: the main Berghain techno hall with a 60,000 watt sound system and the Panorama Bar above it with electronic and house music. The club operates Friday midnight to Monday morning without interruption. Admission is selective at the door.', whyHidden:'Not hidden — but the door policy means it requires genuine intent. The selection process exists to maintain the internal atmosphere; those admitted find something genuinely extraordinary.', bestTime:'Sunday afternoon when the dance floor and the bar are at their most relaxed', howToGet:'S3/S5/S7/S9 to Ostbahnhof; walk north to Am Wriezener Bahnhof.', whatToAvoid:'Weekend midnight is the hardest entry; Sunday afternoon is more accessible', hiddennessScore:3, category:'Bar / Nightlife', interests:['nightlife'], lat:52.5113, lng:13.4437, address:'Am Wriezener Bahnhof, Friedrichshain, Berlin', entryPrice:'€15–18', photo:'1560969184-10fe8719e047' },
  { id:'berlin-east-side-gallery-dawn', name:'East Side Gallery at Dawn', city:'Berlin', country:'Germany', shortDesc:'The Wall\'s longest painted section — extraordinary at 6am before tour groups arrive', fullDesc:'The 1.3km East Side Gallery on Mühlenstraße, where 118 artists painted the East German Wall in 1990, is famous and crowded during the day. At 6am the paintings are lit by early light, no tour groups are present and the scale of the murals can be properly absorbed.', whyHidden:'Not hidden — but dawn transforms it completely. The Brezhnev-Honecker kiss, Thierry Noir\'s painted heads and the Trabant bursting through the wall are all best experienced without a crowd.', bestTime:'6–8am on any weekday', howToGet:'S3/S5/S7/S9 to Ostbahnhof; walk west along the Wall.', whatToAvoid:'Any time after 10am in summer', hiddennessScore:2, category:'Gallery / Art', interests:['art','photography','history'], lat:52.5041, lng:13.4393, address:'Mühlenstraße, Friedrichshain, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-grünewald-grunewald-forest', name:'Grunewald Forest', city:'Berlin', country:'Germany', shortDesc:'3,000 hectares of pine and birch forest within Berlin city limits — wild swimming and silence', fullDesc:'A 3,000-hectare forest in southwestern Berlin with sandy tracks, lakes (Schlachtensee, Krumme Lanke) for outdoor swimming, and enough space to get genuinely lost. The forest feels nothing like a city park — it is a genuine forest where deer and wild boar are sighted. Combined with Teufelsberg, the forest offers 4+ hours of woodland walking.', whyHidden:'Requires the S7 to Grunewald station. Most tourists don\'t associate Berlin with wilderness; Berliners use this forest every weekend.', bestTime:'Autumn for the birch colour; any summer morning for lake swimming', howToGet:'S7 to Grunewald; the forest begins immediately at the station.', whatToAvoid:'Swimming lakes crowded on summer weekends', hiddennessScore:5, category:'Park / Green Space', interests:['hiking','beaches','relaxation'], lat:52.4817, lng:13.2214, address:'Grunewald Forest, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-kreuzberg-oranienstraße', name:'Oranienstraße at Night', city:'Berlin', country:'Germany', shortDesc:'Kreuzberg\'s main artery — where the city\'s alternative identity was forged', fullDesc:'Oranienstraße in SO36 (Kreuzberg) was the epicentre of Berlin\'s punk, queer and Turkish communities from the 1970s onwards. Today the bars, record shops and community spaces remain alongside Turkish restaurants and new cocktail bars. The May Day demonstrations still begin here. The street\'s political history is inscribed in every shopfront.', whyHidden:'Kreuzberg tourists focus on the Landwehrkanal and Bergmannstraße. Oranienstraße is more politically and culturally charged.', bestTime:'Any evening from 8pm; 1 May for the street festival', howToGet:'U1/U8 to Kottbusser Tor; walk east on Oranienstraße.', whatToAvoid:'Nothing specific', hiddennessScore:5, category:'Neighbourhood / District', interests:['nightlife','art'], lat:52.4978, lng:13.4204, address:'Oranienstraße, Kreuzberg, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id:'berlin-c-o-berlin', name:'C/O Berlin Photography Museum', city:'Berlin', country:'Germany', shortDesc:'World-class photography in a former US Army post office in Charlottenburg', fullDesc:'A photography exhibition space in the former America Haus (later US Army post office) in Charlottenburg, presenting the finest international photography exhibitions in Germany. The programme is consistently on a par with the Foam in Amsterdam; the building is extraordinary Fifties modernism.', whyHidden:'In Charlottenburg, a western district tourists bypass for Mitte and Kreuzberg. Photography exhibition spaces don\'t attract mass tourism.', bestTime:'Weekday afternoons; check the exhibition programme', howToGet:'S5/S7/S9 to Savignyplatz; or U2 to Zoologischer Garten.', whatToAvoid:'Between exhibitions the space is closed', hiddennessScore:6, category:'Gallery / Art', interests:['art','photography','museums'], lat:52.5051, lng:13.3281, address:'Hardenbergstraße 22-24, Charlottenburg, Berlin', entryPrice:'€12', photo:'1560969184-10fe8719e047' },
  { id:'berlin-prater-biergarten', name:'Prater Biergarten', city:'Berlin', country:'Germany', shortDesc:'Berlin\'s oldest beer garden — open since 1837 in a Prenzlauer Berg courtyard', fullDesc:'Operating since 1837, the Prater is the oldest beer garden in Berlin, with a large chestnut-shaded garden and a small stage for folk music on weekends. The crowd is local, the beer is excellent and the kitchen serves classic German food. Nothing about the Prater has been significantly altered in decades.', whyHidden:'In Prenzlauer Berg, which tourists visit for the Mauerpark. The Prater is one street east and far more genuinely Berlin.', bestTime:'Summer afternoons from 3pm; weekday evenings', howToGet:'U2 to Eberswalder Straße; Prater is on Kastanienallee 7-9.', whatToAvoid:'Very busy on summer Saturday afternoons', hiddennessScore:4, category:'Bar / Nightlife', interests:['food','nightlife'], lat:52.5398, lng:13.4073, address:'Kastanienallee 7-9, Prenzlauer Berg, Berlin', entryPrice:'Free entry', photo:'1560969184-10fe8719e047' },
  { id:'berlin-zionskirche', name:'Zionskirche', city:'Berlin', country:'Germany', shortDesc:'The Protestant church where the East German civil rights movement was born', fullDesc:'A 19th-century church in Mitte where the East German peace movement, environmental groups and opposition politicians held meetings under ecclesiastical protection in the 1980s — the only space in the GDR where unsanctioned political discussion could take place. The church square has a neighbourhood market on Saturdays and is surrounded by good cafés.', whyHidden:'In the Mitte/Prenzlauer Berg border area, overlooked for the better-known Gethsemane Church. The role of this specific church in the collapse of the GDR is poorly known.', bestTime:'Saturday morning for the market; any time for the church exterior', howToGet:'U8 to Rosenthaler Platz; walk north to Zionskirchplatz.', whatToAvoid:'Interior only accessible during services', hiddennessScore:7, category:'Spiritual / Ritual', interests:['history','monuments'], lat:52.5314, lng:13.4031, address:'Zionskirchplatz, Mitte, Berlin', entryPrice:'Free', photo:'1560969184-10fe8719e047' },
  { id: 'berlin-scheunenviertel', name: 'Scheunenviertel — Barn Quarter', city: 'Berlin', country: 'Germany', shortDesc: 'Berlin\'s pre-war Jewish quarter — courtyards, galleries and the best falafel in Europe', fullDesc: 'The Scheunenviertel (Barn Quarter) in Mitte was the heart of Berlin\'s Eastern European Jewish immigrant community from the 17th century until 1938. The Hackesche Höfe complex of interconnected courtyards, the New Synagogue on Oranienburger Strasse, and the surrounding streets still show the Art Nouveau apartment buildings of the district. The area now has excellent galleries, independent shops and restaurants.', whyHidden: 'Adjacent to the tourist Hackescher Markt but requiring penetration of the courtyard network to find the best of it.', bestTime: 'Any weekday morning for the galleries; Thursday evening for the weekly art openings', howToGet: 'S-Bahn to Hackescher Markt.', whatToAvoid: 'Weekend days are crowded around the Hackesche Höfe; the side streets are always quieter', hiddennessScore: 4, category: 'Neighbourhood', interests: ['neighbourhood', 'art', 'history'], lat: 52.5260, lng: 13.4063, address: 'Hackesche Höfe, Rosenthaler Strasse 40-41, Berlin', entryPrice: 'Free', photo: '1528727548-8e814d0cb3a2' },

  { id: 'berlin-tempelhofer-feld', name: 'Tempelhofer Feld (Former Airport)', city: 'Berlin', country: 'Germany', shortDesc: 'The world\'s largest park — Hitler\'s airport converted to a 355-hectare public space', fullDesc: 'Tempelhof airport, the former Nazi showcase built in 1936, was closed in 2008 and its 355-hectare runways and airfield converted into a public park. The runways are now used for cycling, rollerblading, kite-flying, urban gardening and a weekly flea market. The terminal building — one of the world\'s largest structures when built — is used for events.', whyHidden: 'Known to Berliners but less on tourist maps. The experience of cycling the original 2km runway in the middle of Berlin, with the Nazi-era terminal visible in the background, is genuinely extraordinary.', bestTime: 'Summer weekends for the full life of the park; weekday evenings for quieter cycling', howToGet: 'U6 to Platz der Luftbrücke; the park entrance is directly at the station.', whatToAvoid: 'Winter is cold and exposed — the park is best from April to October', hiddennessScore: 5, category: 'Park', interests: ['park', 'history', 'unusual'], lat: 52.4732, lng: 13.4027, address: 'Tempelhofer Feld, Tempelhof, Berlin', entryPrice: 'Free', photo: '1500534314-c7e7a1a5a667' },

  { id: 'berlin-berlinische-galerie', name: 'Berlinische Galerie', city: 'Berlin', country: 'Germany', shortDesc: 'Berlin\'s own art museum — Dada, New Objectivity and Wall-era art in a former glass factory', fullDesc: 'The Berlinische Galerie in Kreuzberg focuses specifically on Berlin art from 1870 to the present — the extraordinary Berlin Dada collection (Grosz, Heartfield, Hausmann), the Jewish avant-garde, divided-Berlin photography, and the Wall-related art. The building — a converted glass factory — has excellent architectural details.', whyHidden: 'The major Berlin art museums (Gemäldegalerie, Hamburger Bahnhof) overshadow this more specific collection. The Dada room alone is world-class.', bestTime: 'Any weekday; Thursday evenings are free and attract a local art crowd', howToGet: 'U1/U3/U8 to Kottbusser Tor or U6 to Hallesches Tor.', whatToAvoid: 'Closed Tuesdays', hiddennessScore: 5, category: 'Art', interests: ['art', 'history', 'neighbourhood'], lat: 52.5017, lng: 13.4022, address: 'Alte Jakobstrasse 124-128, Berlin', entryPrice: '€8 (free Thursday evening)', photo: '1547826083-3d57abb0c2b7' },

  { id: 'berlin-tempodrom-arena-di-cielo', name: 'Arena Berlin and Badeschiff', city: 'Berlin', country: 'Germany', shortDesc: 'A floating outdoor swimming pool in the Spree river — in a shipping container', fullDesc: 'The Badeschiff (bathing ship) is a swimming pool constructed inside a converted barge moored in the Spree River at Arena Berlin, filled with clean filtered river water. In summer it is an outdoor pool floating in the river; in winter it is enclosed in a temporary structure and heated. The Arena complex has Berlin\'s best concert venue in a former East Berlin bus depot.', whyHidden: 'In the Treptow district on the Spree, south of Kreuzberg. The Badeschiff is known but the combination with the Arena concert venue makes this the most interesting cultural waterfront in Berlin.', bestTime: 'Summer (June–September) for the outdoor swimming; evening concerts year-round', howToGet: 'S-Bahn to Treptower Park.', whatToAvoid: 'The outdoor pool requires a swim test or evidence of swimming ability; it fills on hot weekdays', hiddennessScore: 6, category: 'Unusual', interests: ['unusual', 'nightlife', 'park'], lat: 52.4970, lng: 13.4580, address: 'Eichenstrasse 4, Treptow, Berlin', entryPrice: 'Pool €6; concerts vary', photo: '1500534314-c7e7a1a5a667' },

  { id: 'berlin-pfefferberg-brewery', name: 'Pfefferberg — The Alternative Cultural Beer Garden', city: 'Berlin', country: 'Germany', shortDesc: '1890s brewery complex converted to a cultural venue — beer garden, cinema, gallery', fullDesc: 'Pfefferberg in Prenzlauer Berg occupies a massive 1890s brewery complex with a beer garden, cinema, exhibition halls, theatre and the Theaterdiscounter. The complex has retained the original red-brick brewery buildings and is used year-round for Berlin\'s independent cultural scene — far less commercial than the Kulturbrauerei nearby.', whyHidden: 'The Kulturbrauerei is better known. Pfefferberg has a more genuinely independent atmosphere and a better beer garden in the original brewery courtyard.', bestTime: 'Summer evenings for the beer garden; any time for cinema or exhibitions', howToGet: 'U2 to Senefelderplatz.', whatToAvoid: 'The complex is active only when events are programmed — check the schedule', hiddennessScore: 6, category: 'Nightlife', interests: ['nightlife', 'art', 'architecture'], lat: 52.5363, lng: 13.4154, address: 'Schönhauser Allee 176, Prenzlauer Berg, Berlin', entryPrice: 'Free (beer garden); events vary', photo: '1414235077428-338989a2e8c0' },

  { id: 'berlin-jungfernheide-park', name: 'Jungfernheide Forest Park', city: 'Berlin', country: 'Germany', shortDesc: 'Berlin\'s most undervisited large park — forest, lake, lido and complete solitude', fullDesc: 'Jungfernheide is a 557-hectare forest park in Charlottenburg-Nord with a swimming lake (the Freibad Jungfernheide), forest walking paths and a bird reserve. Unlike the more famous Tiergarten, Jungfernheide is entirely local — used by west Berlin residents and almost never by tourists, despite being larger than most Berlin parks.', whyHidden: 'North of the tourist zones and accessed by U7. Berlin\'s parks are undervalued in general; Jungfernheide is the most undervalued of the large ones.', bestTime: 'Summer mornings for the outdoor lido; autumn for the forest walks', howToGet: 'U7 to Jungfernheide.', whatToAvoid: 'The outdoor swimming area is closed in winter', hiddennessScore: 7, category: 'Nature', interests: ['nature', 'park', 'unusual'], lat: 52.5399, lng: 13.2977, address: 'Jungfernheideweg 1, Charlottenburg-Nord, Berlin', entryPrice: 'Free (lido €5)', photo: '1500534314-c7e7a1a5a667' },

  { id: 'berlin-hamburger-bahnhof-annex', name: 'Hamburger Bahnhof Museum für Gegenwart', city: 'Berlin', country: 'Germany', shortDesc: 'Berlin\'s best contemporary art museum in a former railway terminus — enormous Beuys room', fullDesc: 'The Hamburger Bahnhof is Berlin\'s contemporary art museum — a converted 1847 railway terminus with massive nave spaces housing Cy Twombly canvases, the complete Joseph Beuys "The Pack" installation (50 VW campers on gallery stairs), and major works by Anselm Kiefer and Jeff Koons. The Beuys room is one of the great rooms in any contemporary art museum.', whyHidden: 'The Pergamon and Neues Museum attract all tourist attention. Hamburger Bahnhof is 500 metres away and the contemporary art collection is world-class.', bestTime: 'Any weekday morning; the Beuys room is most atmospheric before noon', howToGet: 'S-Bahn to Hauptbahnhof.', whatToAvoid: 'Closed Mondays; temporary exhibitions require separate tickets', hiddennessScore: 4, category: 'Art', interests: ['art', 'architecture', 'history'], lat: 52.5231, lng: 13.3634, address: 'Invalidenstrasse 50-51, Mitte, Berlin', entryPrice: '€14', photo: '1547826083-3d57abb0c2b7' },

  { id: 'berlin-mauerpark-karaoke', name: 'Mauerpark Sunday Market and Open-Air Karaoke', city: 'Berlin', country: 'Germany', shortDesc: 'The largest and most bizarre Sunday flea market in Germany — plus 2,000-person outdoor karaoke', fullDesc: 'Mauerpark in Prenzlauer Berg is the site of the former Berlin Wall death strip, now a public park. On Sunday mornings the largest flea market in Berlin covers the park; in the afternoon, the Mauerpark amphitheatre hosts Barry Koster\'s famous open-air karaoke — 2,000 people watching solo singers on an outdoor stage, cheering from the hillside. Free, spontaneous, extraordinary.', whyHidden: 'The flea market is known; the Sunday karaoke — which has been running for years and is a genuine institution — is less documented. The combination makes Sunday at Mauerpark one of the most enjoyable experiences in Berlin.', bestTime: 'Sunday from 9am (flea market) to 3pm (karaoke begins)', howToGet: 'U8 to Voltastrasse or U2 to Eberswalder Strasse.', whatToAvoid: 'The flea market is extremely crowded on warm Sundays; arrive before noon for space', hiddennessScore: 4, category: 'Market', interests: ['market', 'nightlife', 'unusual'], lat: 52.5440, lng: 13.4029, address: 'Bernauer Strasse 63-64, Prenzlauer Berg, Berlin', entryPrice: 'Free', photo: '1555041469-db61523df9a4' },

  { id: 'berlin-east-side-gallery-detail', name: 'East Side Gallery — Inner Wall History', city: 'Berlin', country: 'Germany', shortDesc: 'The Wall\'s interior infrastructure — guard towers, death strip detail, actual escape routes', fullDesc: 'The East Side Gallery is known but most visitors see only the painted outer surface. The inner Wall history — the 100-metre death strip between the inner and outer wall, the guard tower positions, the documented escape attempts including vehicle charges through the barrier — is documented in the adjacent Berlin Wall Memorial at Bernauer Strasse. The full picture requires both sites.', whyHidden: 'The East Side Gallery painting is visited; the Bernauer Strasse documentation of actual Wall mechanics is the place to understand what the Wall meant. A preserved section of the full death strip infrastructure is here.', bestTime: 'Any time; the Bernauer Strasse memorial is more powerful in grey weather', howToGet: 'U8 to Bernauer Strasse for the memorial; S-Bahn to Warschauer Strasse for the gallery.', whatToAvoid: 'The two sites are 3km apart — plan for each separately', hiddennessScore: 4, category: 'History', interests: ['history', 'art', 'architecture'], lat: 52.5354, lng: 13.3886, address: 'Bernauer Strasse 119, Berlin', entryPrice: 'Free', photo: '1594736797933-d0501ba2fe65' },

  { id: 'berlin-cafe-anna-blume', name: 'Prenzlauer Berg Morning Café Culture', city: 'Berlin', country: 'Germany', shortDesc: 'The original East Berlin gentrification neighbourhood — Sunday brunch culture, art, flowers', fullDesc: 'Prenzlauer Berg\'s café culture — centred on Kollwitzplatz, Helmholtzplatz and the surrounding streets — is Berlin\'s most complete neighbourhood breakfast and brunch culture. Café Anna Blume with its over-the-top floral decoration, the Lithuanian Café at Kastanienallee, and the organic food market at Kollwitzplatz on Saturday and Tuesday represent a way of life specific to post-unification Berlin.', whyHidden: 'Tourists go to Mitte and Kreuzberg. Prenzlauer Berg is residential and its specific café culture requires walking the residential streets rather than the tourist zones.', bestTime: 'Sunday morning from 10am for the full brunch culture', howToGet: 'U2 to Eberswalder Strasse.', whatToAvoid: 'Weekend mornings have queues for popular cafés — arrive before 10am or after 1pm', hiddennessScore: 4, category: 'Food', interests: ['food', 'neighbourhood', 'art'], lat: 52.5395, lng: 13.4147, address: 'Kollwitzplatz, Prenzlauer Berg, Berlin', entryPrice: 'Free', photo: '1414235077428-338989a2e8c0' },

  { id: 'berlin-museum-der-dinge', name: 'Museum der Dinge (Museum of Things)', city: 'Berlin', country: 'Germany', shortDesc: 'The Werkbund collection of designed objects — 20,000 things from 1900 to the present', fullDesc: 'The Museum der Dinge (Museum of Things) in Kreuzberg is the archive of the Werkbund — the German design movement that preceded Bauhaus — with 20,000 objects representing German and international design from 1900 to the present. The collection ranges from AEG products designed by Peter Behrens to DDR household objects. The installation method — objects on shelves floor to ceiling — is extraordinary.', whyHidden: 'In a Kreuzberg courtyard, not obviously accessible. The Werkbund archive is the most concentrated collection of 20th-century German design objects in existence.', bestTime: 'Any Saturday or Sunday when the museum is open', howToGet: 'U1/U3 to Görlitzer Bahnhof.', whatToAvoid: 'Open only on weekends (Friday–Sunday) — check hours carefully', hiddennessScore: 7, category: 'Museum', interests: ['art', 'history', 'unusual'], lat: 52.4983, lng: 13.4355, address: 'Oranienstrasse 25, Kreuzberg, Berlin', entryPrice: '€6', photo: '1504966191903-6f9e6c4b8c4a' },

  { id: 'berlin-grunewald-teufelsberg', name: 'Teufelsberg — NSA Spy Station Ruins', city: 'Berlin', country: 'Germany', shortDesc: 'Abandoned Cold War spy station on a hill made from WWII rubble — radical open-air gallery', fullDesc: 'Teufelsberg (Devil\'s Mountain) in the Grunewald is a hill created from 26 million cubic metres of WWII rubble. On its summit is the abandoned Field Station Berlin — the NSA\'s Cold War listening station, decommissioned in 1992, now an extraordinary ruin with enormous domed radomes (radar covers) that act as natural reverb chambers. Street artists have covered the interior.', whyHidden: 'In the Grunewald forest west of Berlin, requiring a specific journey. The combination of Cold War history, extraordinary acoustics in the radomes and street art makes it unique.', bestTime: 'Weekend days when guided tours are running (the site requires a guide to enter)', howToGet: 'Bus 115 from S-Bahn Heerstrasse to Teufelssee; 20-minute walk through the forest.', whatToAvoid: 'Independent entry is not permitted — join a guided tour (€10, runs Friday–Sunday)', hiddennessScore: 7, category: 'History', interests: ['history', 'unusual', 'underground'], lat: 52.4935, lng: 13.2380, address: 'Teufelsberg, Grunewald, Berlin', entryPrice: '€10 (guided tour)', photo: '1594736797933-d0501ba2fe65' },

  { id: 'berlin-friedrichshain-park', name: 'Volkspark Friedrichshain', city: 'Berlin', country: 'Germany', shortDesc: 'The oldest public park in Berlin — anti-fascist memorial, WWII rubble hills, fairy-tale fountain', fullDesc: 'Volkspark Friedrichshain (1848) is the oldest public park in Berlin, with the Märchenbrunnen (Fairy-tale Fountain, 1913) — an extraordinary Neo-Baroque fountain complex with 106 figures from German folk tales — and two rubble hills (Trümmerberge) created from WWII debris containing bunker ruins inside. The park has an open-air cinema in summer and an open-air disco at Kino in der Kulturbrauerei.', whyHidden: 'Adjacent to Friedrichshain\'s nightlife but parks are generally undervisited by tourists. The fairy-tale fountain is one of the strangest large-scale sculptural installations in Germany.', bestTime: 'Mornings for the park; summer evenings for the open-air cinema', howToGet: 'U5 to Frankfurter Tor.', whatToAvoid: 'Nothing — the park is safe and open 24 hours', hiddennessScore: 5, category: 'Park', interests: ['park', 'history', 'unusual'], lat: 52.5241, lng: 13.4514, address: 'Am Friedrichshain, Friedrichshain, Berlin', entryPrice: 'Free', photo: '1500534314-c7e7a1a5a667' },
];
